query:
DELETE sp1 FROM search_progress sp1
INNER JOIN search_progress sp2
WHERE sp1.id > sp2.id AND sp1.searchId = sp2.searchId AND sp1.source = sp2.source;

ALTER TABLE search_progress ADD UNIQUE KEY uq_search_source (searchId, source);

